content.css:
/**
 * OKVIZ common styles v1.0.5
 * Update: Mar 24, 2020
 */
@font-face {
  font-family: 'icons';
  src: url('data:application/font-woff;base64,');
}
@font-face {
  font-family: 'wf_standard-font';
  src: url('data:application/x-font-woff;base64,');
}
@font-face {
  font-family: 'wf_standard-font_light';
  src: url('data:application/x-font-woff;base64,');
}
/* Effect */
@-webkit-keyframes sk-scaleout {
  0% {
    -webkit-transform: scale(0);
  }
  100% {
    -webkit-transform: scale(1);
    opacity: 0;
  }
}
@keyframes sk-scaleout {
  0% {
    -webkit-transform: scale(0);
    transform: scale(0);
  }
  100% {
    -webkit-transform: scale(1);
    transform: scale(1);
    opacity: 0;
  }
}
/** Scrollbar **/
*::-webkit-scrollbar {
  width: 8px;
  height: 8px;
  background-color: transparent;
  border-radius: 8px;
}
*::-webkit-scrollbar-thumb {
  background: #c8c8c8 !important;
  border-radius: 8px;
}
*::-webkit-scrollbar-track-piece {
  background: #f4f4f4;
  border-radius: 8px;
}
* {
  -ms-overflow-style: -ms-autohiding-scrollbar;
  -ms-scrollbar-track-color: none;
  -ms-scrollbar-arrow-color: #c8c8c8 !important;
  -ms-scrollbar-face-color: #c8c8c8 !important;
  -webkit-font-smoothing: antialiased;
}
/** Alerts **/
.hidden {
  display: none;
}
.slide-alert {
  cursor: pointer;
}
.alert-icon {
  margin: 0;
  display: block;
}
.alert-icon:after {
  content: '\e730';
  font-family: 'icons';
  font-style: normal;
  text-align: center;
  font-size: 20px;
  line-height: 1.5;
}
.alert-icon.marketplace-icon:after {
  content: '\e719';
}
.alert-icon.error-icon:after {
  content: '\e72f';
}
.alert-icon.error2-icon:after {
  content: '\ea39';
}
.alert-icon.big-error-icon:after {
  content: '\ea39';
  font-size: 35px;
  line-height: 1;
}
.alert-icon.big-upgrade-icon:after {
  content: '\f133';
  font-size: 35px;
  line-height: 1;
}
.alert-icon.success-icon:after {
  content: '\e930';
}
.alert-icon.download-icon:after {
  content: '\e896';
}
.alert-icon.upgrade-icon:after {
  content: '\f133';
}
.alert-icon.bookmarks-icon:after {
  content: '\edff';
}
.alert-icon.themes-icon:after {
  content: '\ecff';
}
.alert-icon.paste-icon:after {
  content: '\e77f';
}
.alert-icon.bell-icon:after {
  content: '\ea8f';
}
.alert-icon.plugin-icon:after {
  content: '\ea86';
}
.alert-icon.idea-icon:after {
  content: '\ea80';
}
.alert-icon.update-icon:after {
  content: '\e895';
}
.alert-icon.click-icon:after {
  content: '\e901';
}
.alert-icon.multiple-icon:after {
  content: '\e8a9';
}
.alert-icon.dynamic-icon:after {
  content: '\e945';
}
.alert-icon.states-icon:after {
  content: '\ed02';
}
.alert-icon.tooltips-icon:after {
  content: '\f7df';
}
.logo {
  font-size: 40px;
  line-height: 1.1;
  color: #00a99d;
  position: absolute;
  z-index: 9999999999999;
  text-decoration: none;
}
.logo:after {
  content: '\e900';
  font-family: 'icons';
  font-style: normal;
  text-align: center;
  font-size: 1em;
}
/** Landing screen **/
.visual-landing {
  width: 100vw;
  height: 100vh;
  font-family: "Segoe UI Light", wf_segoe-ui_bold, helvetica, arial, sans-serif;
  overflow: hidden;
}
.visual-landing .watermark {
  height: 100%;
  width: auto;
}
.visual-landing .watermark svg {
  width: 100%;
  height: 100%;
}
.visual-landing .logo {
  bottom: 0;
  right: 0;
  background: #fff;
  font-size: 30px;
  color: #C8C8C8;
}
.visual-landing .logo:after {
  content: '\e900';
}
.visual-landing .logo:hover {
  color: #00a99d;
}
@media only screen and (max-width: 250px), only screen and (max-height: 100px) {
  .visual-landing .logo {
    font-size: 16px;
  }
}
/* Body */
body {
  font-family: "Segoe UI", wf_segoe-ui_normal, helvetica, arial, sans-serif;
  shape-rendering: geometricPrecision;
}
.visual-header {
  position: absolute;
  right: 12px;
  z-index: 99999999;
  display: none;
}
body:hover .visual-header {
  display: block;
}
.visual-header {
  top: 0;
}
.version-info {
  font-size: 11px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
  color: #ccc;
  padding: 0 5px;
  clear: both;
}

.axis {
  font-size: 11px;
}
.axis path {
  display: none;
}
.axis line {
  stroke: #e9e9e9 !important;
  shape-rendering: crispEdges;
}


